import sys

def sos_dp(n, f):
    """Compute sum over subsets for each bitmask."""
    sos = f[:]
    for i in range(n):
        for mask in range(1 << n):
            if mask & (1 << i):
                sos[mask] += sos[mask ^ (1 << i)]
    return sos


