fn sos_dp(n: usize, f: &[i64]) -> Vec<i64> {
    let size = 1 << n;
    let mut sos: Vec<i64> = f.to_vec();

    for i in 0..n {
        for mask in 0..size {
            if mask & (1 << i) != 0 {
                sos[mask] += sos[mask ^ (1 << i)];
            }
        }
    }
    sos
}

