export function sosDp(n: number, f: number[]): number[] {
    const size = 1 << n;
    const sos = [...f];

    for (let i = 0; i < n; i++) {
        for (let mask = 0; mask < size; mask++) {
            if (mask & (1 << i)) {
                sos[mask] += sos[mask ^ (1 << i)];
            }
        }
    }
    return sos;
}

